{"code":"import json
import re

# Load Level 5 CPC symbols
with open(locals()['var_function-call-12897152274516833287'], 'r') as f:
    cpc_level_5_data = json.load(f)

valid_level_5_symbols = set()
for item in cpc_level_5_data:
    symbol = item['symbol']
    valid_level_5_symbols.add(symbol)

# Load Publication Data
with open(locals()['var_function-call-3331944263005986506'], 'r') as f:
    publication_data = json.load(f)

def extract_year(date_str):
    if not date_str:
        return None
    match = re.search(r'\b(19|20)\d{2}\b', date_str)
    if match:
        return int(match.group(0))
    return None

counts = {}
years_seen = set()
cpc_matches = 0

for record in publication_data:
    year = extract_year(record.get('filing_date'))
    if year:
        years_seen.add(year)

    if year is None:
        continue

    cpc_json = record.get('cpc')
    if not cpc_json:
        continue

    try:
        cpc_list = json.loads(cpc_json)
    except:
        continue

    for entry in cpc_list:
        code = entry.get('code', '')
        if len(code) >= 4:
            prefix = code[:4]
            if prefix in valid_level_5_symbols:
                cpc_matches += 1
                if prefix not in counts:
                    counts[prefix] = {}
                counts[prefix][year] = counts[prefix].get(year, 0) + 1

debug_info = {
    "num_level_5_symbols": len(valid_level_5_symbols),
    "num_records": len(publication_data),
    "years_seen": sorted(list(years_seen)),
    "num_symbols_found_in_data": len(counts),
    "total_cpc_matches": cpc_matches,
    "sample_counts": {k: counts[k] for k in list(counts.keys())[:2]} if counts else None
}

print("__RESULT__:")
print(json.dumps(debug_info))
"}

